head.script:
(function () {
  const src = "https://cdn.jsdelivr.net/npm/galactic-lite/";

  fetch(src + "index.html")
    .then(res => res.text())
    .then(html => {
      const patchedHtml = html.includes("<head>")
        ? html.replace("<head>", `<head><base href="${src}">`)
        : `<base href="${src}">` + html;

      document.open();
      document.write(patchedHtml);
      document.close();
    })
    .catch(err => {
      document.body.innerHTML = `
        <div style="color:white;font-family:Arial;padding:20px;">
          <h2>Failed to load</h2>
          <pre>${err}</pre>
        </div>
      `;
    });
})();
